import React, { useState } from "react";

export default function ChatSettings() {
  const [chatInput, setChatInput] = useState("");
  const [chatMessages, setChatMessages] = useState([]);
  const [showChat, setShowChat] = useState(false);
  const [toast, setToast] = useState(null);

  const sendChatMessage = () => {
    if (chatInput.trim() === "") return;
    setChatMessages([...chatMessages, chatInput]);
    setChatInput("");
    setToast("Tin nhắn đã gửi!");
    setTimeout(() => setToast(null), 2000);
  };

  return (
    <div style={{ position: "relative", padding: 20 }}>
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nuk8gi0s_expires_30_days.png"
        style={{ width: 45, height: 45, cursor: "pointer" }}
        alt="settings-icon"
        onClick={() => setShowChat(!showChat)}
      />

      {showChat && (
        <div style={{ position: "absolute", top: 60, right: 0, width: 300, border: "1px solid #ccc", padding: 10, background: "#fff" }}>
          <div style={{ maxHeight: 200, overflowY: "auto", marginBottom: 10 }}>
            {chatMessages.length === 0 ? (
              <p>Chưa có tin nhắn nào</p>
            ) : (
              chatMessages.map((msg, i) => <div key={i} style={{ background: "#eee", padding: 5, margin: 2 }}>{msg}</div>)
            )}
          </div>
          <div style={{ display: "flex", gap: 5 }}>
            <input
              type="text"
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              style={{ flex: 1 }}
              placeholder="Nhập tin nhắn..."
            />
            <button onClick={sendChatMessage}>Gửi</button>
          </div>
        </div>
      )}

      {toast && <div style={{ position: "fixed", bottom: 20, right: 20, background: "black", color: "white", padding: 10 }}>{toast}</div>}
    </div>
  );
}
